                db.execSQL("ALTER TABLE words ADD COLUMN definitionNative TEXT")
                db.execSQL("ALTER TABLE words ADD COLUMN exampleNative TEXT")
                db.execSQL("DELETE FROM words WHERE setId IN (101, 102, 103)")
